const data = $input.first().json.body || $input.first().json;
const { type, price, textDescription, imageUrl } = data;

const typeLabel = type === 'product' ? 'producto' : 'servicio';

let systemPrompt = `Eres un experto en marketing y copywriting para pequeños negocios en México y Latinoamérica.
Tu misión: generar nombres atractivos y descripciones persuasivas que vendan.
Siempre responde SOLO con JSON válido, sin texto extra, sin markdown, sin bloques de código.`;

let userText = `Analiza este ${typeLabel} y genera contenido profesional para venderlo online.

Datos del ${typeLabel}:
- Tipo: ${typeLabel}
- Precio: $${price} MXN`;

if (textDescription && textDescription.trim()) {
  userText += `\n- Descripción del propietario: "${textDescription.trim()}"`;
}

userText += `\n\nResponde ÚNICAMENTE con este JSON exacto (sin nada más):
{
  "name": "nombre corto y atractivo (máximo 60 caracteres)",
  "description": "descripción profesional y persuasiva de 80-150 palabras, destaca beneficios y valor",
  "shortDescription": "frase de venta poderosa para redes sociales (máximo 140 caracteres)",
  "category": "categoría del ${typeLabel} en 1-3 palabras",
  "suggestedSku": "código identificador en mayúsculas sin espacios, ejemplo: BOLSA-ARTESANAL-01"
}`;

const messages = [];

// Add image as vision input if provided
if (imageUrl && (imageUrl.startsWith('http') || imageUrl.startsWith('data:'))) {
  messages.push({
    role: 'user',
    content: [
      { type: 'text', text: userText },
      { type: 'image_url', image_url: { url: imageUrl } }
    ]
  });
} else {
  messages.push({ role: 'user', content: userText });
}

const ollamaBody = {
  model: 'llama3.2-vision:latest',
  messages: [
    { role: 'system', content: systemPrompt },
    ...messages
  ],
  stream: false,
  temperature: 0.7
};

return [{ json: { ollamaBody, originalData: data } }];

const ollamaResponse = $input.first().json;
const originalData = $('Build Ollama Prompt').first().json.originalData;

let aiContent;
try {
  const rawContent = ollamaResponse.choices[0].message.content;
  // Remove markdown code fences if model adds them
  const cleaned = rawContent
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();
  aiContent = JSON.parse(cleaned);
} catch (parseError) {
  // Graceful fallback if AI doesn't return valid JSON
  const fallbackName = originalData.textDescription
    ? originalData.textDescription.substring(0, 60)
    : (originalData.type === 'product' ? 'Nuevo Producto' : 'Nuevo Servicio');

  aiContent = {
    name: fallbackName,
    description: originalData.textDescription || 'Descripción generada automáticamente. Por favor edita para personalizar.',
    shortDescription: fallbackName,
    category: 'General',
    suggestedSku: 'ITEM-' + Date.now()
  };
}

return [{
  json: {
    success: true,
    name: (aiContent.name || '').substring(0, 200),
    description: aiContent.description || '',
    shortDescription: (aiContent.shortDescription || '').substring(0, 140),
    category: (aiContent.category || 'General').substring(0, 50),
    suggestedSku: (aiContent.suggestedSku || ('ITEM-' + Date.now())).replace(/\s+/g, '-').toUpperCase(),
    type: originalData.type,
    price: originalData.price
  }
}];
